package everybody.codes.y2024

object Quest1:
  def solve(input: String): Int =
    input
      .map:
        case 'A' => 0
        case 'B' => 1
        case 'C' => 3
      .sum

  def solve2(input: String, groupSize: Int = 2): Int =
    input
      .grouped(groupSize)
      .map: group =>
        val monsters = group.count(_ != 'x')
        val score    = group
          .map:
            case 'A' | 'x' => 0
            case 'B'       => 1
            case 'C'       => 3
            case 'D'       => 5
          .sum
        score + monsters.match
          case 0 | 1 => 0
          case 2     => 2
          case 3     => 6
      .sum

  def solve3(input: String): Int = solve2(input, 3)

  val input =
    ""

  val input2 =
    ""

  val input3 =
    ""
